// Parse incoming foreman update from Tally/Typeform/direct JSON
// Normalize fields and build AI classification prompt
const raw = $input.item.json.body || $input.item.json;

let jobSite = '';
let percentComplete = 0;
let blockers = '';
let photoUrl = '';
let foremanName = '';
let foremanNote = '';

try {
  if (raw.fields && Array.isArray(raw.fields)) {
    // Tally format: fields array with label/value pairs
    const f = raw.fields;
    const find = (keyword) => {
      const match = f.find(x => x.label && x.label.toLowerCase().includes(keyword));
      return match ? String(match.value || '') : '';
    };
    jobSite = find('job') || find('site') || find('project');
    percentComplete = parseInt(find('percent') || find('complete') || find('progress') || '0');
    blockers = find('block') || find('issue');
    photoUrl = find('photo') || find('image');
    foremanName = find('foreman') || find('name');
    foremanNote = find('note') || find('update') || find('comment');
  } else {
    // Direct JSON format
    jobSite = raw.job_site || raw.jobSite || raw.project || '';
    percentComplete = parseInt(raw.percent_complete || raw.percentComplete || raw.progress || '0');
    blockers = raw.blockers || raw.blocker || raw.issues || '';
    photoUrl = raw.photo_url || raw.photoUrl || raw.photo || '';
    foremanName = raw.foreman_name || raw.foremanName || raw.foreman || '';
    foremanNote = raw.foreman_note || raw.foremanNote || raw.note || raw.notes || raw.update || '';
  }
} catch (e) {
  jobSite = raw.job_site || '';
  percentComplete = parseInt(raw.percent_complete || '0');
  blockers = raw.blockers || '';
  photoUrl = raw.photo_url || '';
  foremanName = raw.foreman_name || '';
  foremanNote = raw.foreman_note || '';
}

const prompt = 'You are an AI assistant for a construction company. Analyze this foreman daily update and return ONLY valid JSON.\n\n' +
  'Job Site: ' + jobSite + '\n' +
  'Percent Complete: ' + percentComplete + '%\n' +
  'Blockers: ' + (blockers || 'None reported') + '\n' +
  'Foreman Note: ' + (foremanNote || 'No additional notes') + '\n\n' +
  'Return JSON with these exact fields:\n' +
  '{\n' +
  '  "status": "on_track" or "at_risk" or "blocked",\n' +
  '  "foreman_summary": "one sentence summary of the update",\n' +
  '  "client_summary": "professional 2-3 sentence summary for the property owner. No internal details. Focus on progress and next steps.",\n' +
  '  "next_milestone": "what happens next on this job",\n' +
  '  "risk_factors": ["array of risk factors"],\n' +
  '  "reasoning": "why you classified this status"\n' +
  '}\n\n' +
  'Rules:\n' +
  '- "blocked" = explicit blocker (permits, materials, weather, inspection fail)\n' +
  '- "at_risk" = behind schedule, vague concerns, potential delays\n' +
  '- "on_track" = normal progress, no blockers, on or ahead of schedule';

return [{ json: {
  job_site: jobSite,
  percent_complete: percentComplete,
  blockers: blockers,
  photo_url: photoUrl,
  foreman_name: foremanName,
  foreman_note: foremanNote,
  received_at: new Date().toISOString(),
  prompt: prompt
}}];

// CANONICAL NODE — all downstream nodes reference this
// Parse Claude response and build all downstream data
const response = $('AI Triage (Claude)').item.json;
const input = $('Parse & Build Prompt').item.json;

let parsed;
try {
  const content = (response.content && response.content[0]) ? response.content[0].text : '';
  const match = content.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : content);
} catch (e) {
  // Fallback if AI response cannot be parsed
  parsed = {
    status: input.blockers ? 'blocked' : 'on_track',
    foreman_summary: input.foreman_note || 'Update received',
    client_summary: 'Work is progressing on ' + input.job_site + '. Currently at ' + input.percent_complete + '% completion.',
    next_milestone: 'Continued progress expected',
    risk_factors: input.blockers ? [input.blockers] : [],
    reasoning: 'Fallback — AI response could not be parsed'
  };
}

const status = parsed.status || 'on_track';
const clientSummary = parsed.client_summary || 'Update received for ' + input.job_site;
const foremanSummary = parsed.foreman_summary || input.foreman_note;
const nextMilestone = parsed.next_milestone || 'TBD';
const riskFactors = Array.isArray(parsed.risk_factors) ? parsed.risk_factors : [];

// Pre-build client email content
const clientEmailSubject = input.job_site + ' — Job Update (' + input.percent_complete + '% Complete)';
const clientEmailBody = '<h2>Job Progress Update</h2>' +
  '<p><b>Project:</b> ' + input.job_site + '</p>' +
  '<p><b>Status:</b> ' + status.replace('_', ' ').toUpperCase() + '</p>' +
  '<p><b>Progress:</b> ' + input.percent_complete + '% complete</p>' +
  '<p>' + clientSummary + '</p>' +
  '<p><b>Next Milestone:</b> ' + nextMilestone + '</p>' +
  '<hr><p style="color:#888;font-size:12px;">This update was generated automatically from your contractor\'s daily report.</p>';

// Pre-build owner alert content (used only if blocked)
const ownerAlertSubject = 'BLOCKED: ' + input.job_site + ' — Immediate Attention Required';
const ownerAlertBody = '<h2 style="color:red;">Job Blocked — ' + input.job_site + '</h2>' +
  '<p><b>Foreman:</b> ' + input.foreman_name + '</p>' +
  '<p><b>Blocker:</b> ' + (input.blockers || 'See details below') + '</p>' +
  '<p><b>Progress at block:</b> ' + input.percent_complete + '%</p>' +
  '<p><b>Foreman Note:</b> ' + foremanSummary + '</p>' +
  (riskFactors.length > 0 ? '<p><b>Risk Factors:</b> ' + riskFactors.join(', ') + '</p>' : '') +
  '<hr><p>Take action to unblock this job.</p>';

return [{ json: {
  job_site: input.job_site,
  percent_complete: input.percent_complete,
  blockers: input.blockers,
  photo_url: input.photo_url,
  foreman_name: input.foreman_name,
  foreman_note: input.foreman_note,
  received_at: input.received_at,
  status: status,
  foreman_summary: foremanSummary,
  client_summary: clientSummary,
  next_milestone: nextMilestone,
  risk_factors: riskFactors,
  ai_reasoning: parsed.reasoning || '',
  client_email_subject: clientEmailSubject,
  client_email_body: clientEmailBody,
  owner_alert_subject: ownerAlertSubject,
  owner_alert_body: ownerAlertBody,
  processed_at: new Date().toISOString()
}}];

// Build flat row for Google Sheets append
// Keys must match sheet tab header row exactly
const d = $('Process AI Response').item.json;
return [{ json: {
  'Date': new Date().toISOString().split('T')[0],
  'Job Site': d.job_site || '',
  'Foreman': d.foreman_name || '',
  'Percent Complete': String(d.percent_complete || 0),
  'Status': (d.status || '').toUpperCase(),
  'Foreman Note': (d.foreman_summary || '').substring(0, 200),
  'Client Summary': (d.client_summary || '').substring(0, 200),
  'Blockers': d.blockers || 'None',
  'Client Notified': 'Yes',
  'Photo URL': d.photo_url || ''
}}];

// Prep client notification email
// References canonical Process AI Response node
const d = $('Process AI Response').item.json;
return [{ json: {
  send_to: 'client@example.com',
  email_subject: d.client_email_subject,
  email_body: d.client_email_body
}}];

// Prep owner alert email for blocked jobs
// References canonical Process AI Response node
const d = $('Process AI Response').item.json;
return [{ json: {
  send_to: 'owner@example.com',
  email_subject: d.owner_alert_subject,
  email_body: d.owner_alert_body
}}];

// Webhook response for blocked path
const d = $('Process AI Response').item.json;
return [{ json: {
  success: true,
  job_site: d.job_site,
  status: d.status,
  percent_complete: d.percent_complete,
  actions: ['AI classified as BLOCKED', 'Logged to Google Sheets', 'Client notified via email', 'Owner alerted via email'],
  foreman_summary: d.foreman_summary,
  client_summary: d.client_summary,
  processed_at: d.processed_at
}}];

// Webhook response for on_track/at_risk path
const d = $('Process AI Response').item.json;
return [{ json: {
  success: true,
  job_site: d.job_site,
  status: d.status,
  percent_complete: d.percent_complete,
  actions: ['AI classified as ' + (d.status || '').toUpperCase(), 'Logged to Google Sheets', 'Client notified via email'],
  foreman_summary: d.foreman_summary,
  client_summary: d.client_summary,
  processed_at: d.processed_at
}}];

// Format error details for logging
const e = $input.item.json;
return [{ json: {
  error: true,
  error_message: e.message || 'Unknown error',
  timestamp: new Date().toISOString(),
  workflow: 'Construction Job Progress Tracker'
}}];
